INSERT INTO `comments` VALUES (1108,2509,559163,'Robert Ashman should look at front page of Open Austarlia to see that there have been many votes in Parliament over the years and all of these have been to oppose SSM.\r\n\r\nThere has been a lot of criticism of Coalition MP\' who will continue to vote against SSM even if plebiscite is carried but no one seems to think it appropriate to ask the Green\'s the same Question. They like Donald Trump will view the result as acceptable ONLY IF IT GOES THERE WAY . This of course is why Shorten and ALP now oppose Plebiscite. They will defend to the death the right of others to agree with them but shout abuse if others disagree with them. Racist Homophobe, Sexist. I can not express my views because Triggs will get me if I do.','2016-11-06 10:13:49',NULL,1,'uk.org.publicwhip/debate/2016-10-20.19.1');
